-- ============================================================
-- VHDL: Combinational Logic - MUX, Decoder, Encoder,
--       Priority Encoder, Barrel Shifter
-- ============================================================

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

-- ============================================================
-- 1. 4:1 Multiplexer
-- ============================================================
entity mux4to1 is
    Port (
        D   : in  STD_LOGIC_VECTOR(3 downto 0);
        S   : in  STD_LOGIC_VECTOR(1 downto 0);
        Y   : out STD_LOGIC
    );
end mux4to1;

architecture Behavioral of mux4to1 is
begin
    with S select
        Y <= D(0) when "00",
             D(1) when "01",
             D(2) when "10",
             D(3) when "11",
             '0'  when others;
end Behavioral;

-- ============================================================
-- 2. 2-to-4 Decoder
-- ============================================================
entity decoder2to4 is
    Port (
        A   : in  STD_LOGIC_VECTOR(1 downto 0);
        EN  : in  STD_LOGIC;
        Y   : out STD_LOGIC_VECTOR(3 downto 0)
    );
end decoder2to4;

architecture Behavioral of decoder2to4 is
begin
    process(A, EN)
    begin
        Y <= "0000";
        if EN = '1' then
            case A is
                when "00" => Y <= "0001";
                when "01" => Y <= "0010";
                when "10" => Y <= "0100";
                when "11" => Y <= "1000";
                when others => Y <= "0000";
            end case;
        end if;
    end process;
end Behavioral;

-- ============================================================
-- 3. 4-to-2 Priority Encoder
-- ============================================================
entity priority_encoder4to2 is
    Port (
        I     : in  STD_LOGIC_VECTOR(3 downto 0);
        Y     : out STD_LOGIC_VECTOR(1 downto 0);
        VALID : out STD_LOGIC
    );
end priority_encoder4to2;

architecture Behavioral of priority_encoder4to2 is
begin
    process(I)
    begin
        VALID <= '1';
        if    I(3) = '1' then Y <= "11";
        elsif I(2) = '1' then Y <= "10";
        elsif I(1) = '1' then Y <= "01";
        elsif I(0) = '1' then Y <= "00";
        else  Y <= "00"; VALID <= '0';
        end if;
    end process;
end Behavioral;

-- ============================================================
-- 4. 8-bit Barrel Shifter (Logical Left Shift)
-- ============================================================
entity barrel_shifter8 is
    Port (
        D     : in  STD_LOGIC_VECTOR(7 downto 0);
        SHAMT : in  STD_LOGIC_VECTOR(2 downto 0);
        Y     : out STD_LOGIC_VECTOR(7 downto 0)
    );
end barrel_shifter8;

architecture Behavioral of barrel_shifter8 is
    signal stage0, stage1 : STD_LOGIC_VECTOR(7 downto 0);
begin
    -- Stage 0: shift by 1 if shamt(0)=1
    stage0 <= D(6 downto 0) & '0' when SHAMT(0) = '1' else D;
    -- Stage 1: shift by 2 if shamt(1)=1
    stage1 <= stage0(5 downto 0) & "00" when SHAMT(1) = '1' else stage0;
    -- Stage 2: shift by 4 if shamt(2)=1
    Y      <= stage1(3 downto 0) & "0000" when SHAMT(2) = '1' else stage1;
end Behavioral;

hdl_code.verilog:
// ============================================================
// Verilog HDL: Combinational Logic
// Covers: assign, always @(*), gate primitives,
//         MUX, Decoder, Encoder, Priority Encoder, Barrel Shifter
// ============================================================

// ============================================================
// MODULE 1: Basic Gates using Verilog Primitives
// ============================================================
module basic_gates (
    input  wire a, b,
    output wire y_and, y_or, y_nand, y_nor, y_xor, y_xnor, y_not_a
);
    // Gate primitive instantiations
    and  g1 (y_and,  a, b);      // AND gate
    or   g2 (y_or,   a, b);      // OR gate
    nand g3 (y_nand, a, b);      // NAND gate
    nor  g4 (y_nor,  a, b);      // NOR gate
    xor  g5 (y_xor,  a, b);      // XOR gate
    xnor g6 (y_xnor, a, b);      // XNOR gate
    not  g7 (y_not_a, a);        // NOT gate (single input)
endmodule

// ============================================================
// MODULE 2: Half Adder using assign statements
// ============================================================
module half_adder (
    input  wire a, b,
    output wire sum, carry
);
    assign sum   = a ^ b;   // XOR for sum
    assign carry = a & b;   // AND for carry
endmodule

// ============================================================
// MODULE 3: Full Adder using assign
// ============================================================
module full_adder (
    input  wire a, b, cin,
    output wire sum, cout
);
    assign sum  = a ^ b ^ cin;
    assign cout = (a & b) | (b & cin) | (a & cin);
endmodule

// ============================================================
// MODULE 4: 2:1 MUX - Three styles
// ============================================================

// Style A: Continuous assign with ternary operator
module mux2to1_assign (
    input  wire d0, d1, sel,
    output wire y
);
    assign y = sel ? d1 : d0;  // sel=1 -> d1, sel=0 -> d0
endmodule

// Style B: Using always @(*)
module mux2to1_always (
    input  wire d0, d1, sel,
    output reg  y
);
    always @(*) begin
        if (sel)
            y = d1;
        else
            y = d0;
    end
endmodule

// Style C: Gate-primitive structural
module mux2to1_gates (
    input  wire d0, d1, sel,
    output wire y
);
    wire sel_n, t0, t1;
    not  g1 (sel_n, sel);      // sel_n = ~sel
    and  g2 (t0, d0, sel_n);   // t0 = d0 & ~sel
    and  g3 (t1, d1, sel);     // t1 = d1 & sel
    or   g4 (y, t0, t1);       // y = t0 | t1
endmodule

// ============================================================
// MODULE 5: 4:1 MUX
// ============================================================
module mux4to1 (
    input  wire [3:0] d,       // 4 data inputs
    input  wire [1:0] sel,     // 2-bit select
    output reg        y        // 1-bit output
);
    always @(*) begin
        case (sel)
            2'b00: y = d[0];
            2'b01: y = d[1];
            2'b10: y = d[2];
            2'b11: y = d[3];
            default: y = 1'bx; // Should never occur
        endcase
    end
endmodule

// ============================================================
// MODULE 6: 8:1 MUX (bus-based)
// ============================================================
module mux8to1 (
    input  wire [7:0] d,
    input  wire [2:0] sel,
    output reg        y
);
    always @(*) begin
        y = d[sel]; // Compact vector-index mux
    end
endmodule

// ============================================================
// MODULE 7: 2-to-4 Decoder with Enable
// ============================================================
module decoder2to4 (
    input  wire [1:0] a,      // 2-bit binary input
    input  wire       en,     // Active-high enable
    output reg  [3:0] y       // 4-bit one-hot output
);
    always @(*) begin
        if (!en)
            y = 4'b0000;      // Disabled: all outputs low
        else begin
            case (a)
                2'b00: y = 4'b0001;  // Y[0] active
                2'b01: y = 4'b0010;  // Y[1] active
                2'b10: y = 4'b0100;  // Y[2] active
                2'b11: y = 4'b1000;  // Y[3] active
                default: y = 4'bxxxx;
            endcase
        end
    end
endmodule

// ============================================================
// MODULE 8: 3-to-8 Decoder using assign
// ============================================================
module decoder3to8 (
    input  wire [2:0] a,
    input  wire       en,
    output wire [7:0] y
);
    // Each output is a minterm; active only when enabled
    assign y[0] = en & ~a[2] & ~a[1] & ~a[0];
    assign y[1] = en & ~a[2] & ~a[1] &  a[0];
    assign y[2] = en & ~a[2] &  a[1] & ~a[0];
    assign y[3] = en & ~a[2] &  a[1] &  a[0];
    assign y[4] = en &  a[2] & ~a[1] & ~a[0];
    assign y[5] = en &  a[2] & ~a[1] &  a[0];
    assign y[6] = en &  a[2] &  a[1] & ~a[0];
    assign y[7] = en &  a[2] &  a[1] &  a[0];
endmodule

// ============================================================
// MODULE 9: 4-to-2 Encoder (basic, assumes one-hot input)
// ============================================================
module encoder4to2 (
    input  wire [3:0] i,     // One-hot input
    output reg  [1:0] y,     // 2-bit binary output
    output reg        valid  // At least one input active
);
    always @(*) begin
        valid = |i;           // Reduction OR: any input active?
        case (i)
            4'b0001: y = 2'b00;
            4'b0010: y = 2'b01;
            4'b0100: y = 2'b10;
            4'b1000: y = 2'b11;
            default: y = 2'bxx; // Non-one-hot: undefined
        endcase
    end
endmodule

// ============================================================
// MODULE 10: 4-to-2 Priority Encoder
// ============================================================
module priority_encoder4to2 (
    input  wire [3:0] i,     // Input lines (i[3] = highest priority)
    output reg  [1:0] y,     // Binary encoded output
    output reg        valid  // Active when any input is 1
);
    always @(*) begin
        valid = 1'b1;
        if      (i[3]) y = 2'b11;   // I3 has highest priority
        else if (i[2]) y = 2'b10;
        else if (i[1]) y = 2'b01;
        else if (i[0]) y = 2'b00;
        else begin
            y     = 2'b00;           // No input active
            valid = 1'b0;
        end
    end
endmodule

// ============================================================
// MODULE 11: 8-to-3 Priority Encoder
// ============================================================
module priority_encoder8to3 (
    input  wire [7:0] i,
    output reg  [2:0] y,
    output reg        valid
);
    always @(*) begin
        valid = 1'b1;
        casez (i)                 // casez: treat ? as don't-care
            8'b1xxxxxxx: y = 3'd7;
            8'b01xxxxxx: y = 3'd6;
            8'b001xxxxx: y = 3'd5;
            8'b0001xxxx: y = 3'd4;
            8'b00001xxx: y = 3'd3;
            8'b000001xx: y = 3'd2;
            8'b0000001x: y = 3'd1;
            8'b00000001: y = 3'd0;
            default:    begin
                y = 3'd0;
                valid = 1'b0;
            end
        endcase
    end
endmodule

// ============================================================
// MODULE 12: 4-bit Barrel Shifter (Logical Left Shift)
// ============================================================
module barrel_shifter_4bit_left (
    input  wire [3:0] d,      // 4-bit data input
    input  wire [1:0] shamt,  // Shift amount: 0-3
    output wire [3:0] y       // Shifted output
);
    wire [3:0] stage0;        // After stage 0
    // Stage 0: shift left by 1 if shamt[0]=1
    assign stage0 = shamt[0] ? {d[2:0], 1'b0} : d;
    // Stage 1: shift left by 2 if shamt[1]=1
    assign y      = shamt[1] ? {stage0[1:0], 2'b00} : stage0;
endmodule

// ============================================================
// MODULE 13: 8-bit Barrel Shifter (Multi-mode)
// Modes: 00=LSL, 01=LSR, 10=ASR, 11=ROL
// ============================================================
module barrel_shifter_8bit (
    input  wire [7:0] d,
    input  wire [2:0] shamt,  // Shift amount 0-7
    input  wire [1:0] mode,   // 00:LSL, 01:LSR, 10:ASR, 11:ROL
    output reg  [7:0] y
);
    always @(*) begin
        case (mode)
            2'b00: y = d << shamt;                        // Logical Shift Left
            2'b01: y = d >> shamt;                        // Logical Shift Right
            2'b10: y = $signed(d) >>> shamt;              // Arithmetic Shift Right
            2'b11: y = (d << shamt) | (d >> (8 - shamt)); // Rotate Left
            default: y = 8'hxx;
        endcase
    end
endmodule

// ============================================================
// MODULE 14: 4-bit ALU (Combinational)
// ============================================================
module alu_4bit (
    input  wire [3:0] a, b,
    input  wire [2:0] opcode,
    output reg  [3:0] result,
    output reg        zero, carry_out
);
    reg [4:0] temp;  // 5-bit for carry detection
    always @(*) begin
        carry_out = 1'b0;
        case (opcode)
            3'b000: begin temp = {1'b0, a} + {1'b0, b}; result = temp[3:0]; carry_out = temp[4]; end // ADD
            3'b001: begin temp = {1'b0, a} - {1'b0, b}; result = temp[3:0]; carry_out = temp[4]; end // SUB
            3'b010: result = a & b;         // AND
            3'b011: result = a | b;         // OR
            3'b100: result = a ^ b;         // XOR
            3'b101: result = ~a;            // NOT A
            3'b110: result = a << 1;        // Shift Left
            3'b111: result = a >> 1;        // Shift Right
            default: result = 4'bxxxx;
        endcase
        zero = (result == 4'b0000);
    end
endmodule

