// Industry-grade parameterized barrel shifter
// Supports N-bit data, log2(N)-bit shift amount
// Modes: LSL, LSR, ASR, ROL, ROR
module barrel_shifter #(
    parameter DATA_WIDTH  = 32,
    parameter SHAMT_WIDTH = 5   // log2(32) = 5
) (
    input  wire [DATA_WIDTH-1:0]  d_in,
    input  wire [SHAMT_WIDTH-1:0] shamt,
    input  wire [2:0]             mode,  // 000:LSL 001:LSR 010:ASR 011:ROL 100:ROR
    output reg  [DATA_WIDTH-1:0]  d_out,
    output wire                   overflow  // For shift > data_width
);
    // Internal wire for double-width rotate support
    wire [2*DATA_WIDTH-1:0] doubled;
    assign doubled   = {d_in, d_in};
    assign overflow  = (shamt >= DATA_WIDTH);

    always @(*) begin
        case (mode)
            3'b000: // Logical Shift Left
                d_out = (overflow) ? {DATA_WIDTH{1'b0}} : (d_in << shamt);
            3'b001: // Logical Shift Right
                d_out = (overflow) ? {DATA_WIDTH{1'b0}} : (d_in >> shamt);
            3'b010: // Arithmetic Shift Right (sign extension)
                d_out = (overflow) ? {DATA_WIDTH{d_in[DATA_WIDTH-1]}} :
                        ($signed(d_in) >>> shamt);
            3'b011: // Rotate Left
                d_out = doubled[DATA_WIDTH + DATA_WIDTH - 1 - shamt -: DATA_WIDTH];
            3'b100: // Rotate Right
                d_out = doubled[DATA_WIDTH - 1 - shamt +: DATA_WIDTH];
            default:
                d_out = {DATA_WIDTH{1'bx}};
        endcase
    end
endmodule

