    initial begin
        $display("=== Barrel Shifter Verification ===");
        apply_test(32'hABCD_1234, 5'd4,  3'b000, "LSL by 4 ");
        apply_test(32'hABCD_1234, 5'd8,  3'b001, "LSR by 8 ");
        apply_test(32'hF000_0000, 5'd4,  3'b010, "ASR by 4 ");
