        apply_test(32'hABCD_1234, 5'd8,  3'b100, "ROR by 8 ");
        apply_test(32'hFFFF_FFFF, 5'd31, 3'b000, "LSL by 31");
        apply_test(32'h8000_0000, 5'd31, 3'b010, "ASR by 31");
        $finish;
    end
endmodule

