module fa_nand_only(
    input  wire a, b, cin,
    output wire sum, cout
);
    wire n1,n2,n3,ab_xor,n5,n6,n7,n8;
    nand g1(n1, a, b);
    nand g2(n2, a, n1);
    nand g3(n3, b, n1);
    nand g4(ab_xor, n2, n3);  // a XOR b
    nand g5(n5, ab_xor, cin);
    nand g6(n6, ab_xor, n5);
    nand g7(n7, cin, n5);
    nand g8(sum, n6, n7);     // SUM = ab_xor XOR cin
    nand g9(cout, n1, n5);    // COUT
endmodule

module tb_fa_nand;
    reg a,b,cin; wire sum,cout;
    fa_nand_only dut(.a(a),.b(b),.cin(cin),.sum(sum),.cout(cout));
    initial begin
        $display("A B Cin | Sum Cout");
        for({a,b,cin}=0;{a,b,cin}<8;{a,b,cin}={a,b,cin}+1) begin
            #10; $display("%b %b %b   |  %b    %b",a,b,cin,sum,cout);
        end
    end
endmodule

module gray_to_binary(
    input  wire [3:0] gray,
    output wire [3:0] binary
);
    // MSB passes through directly
    assign binary[3] = gray[3];
    // Each binary bit XORs with next higher binary bit
    assign binary[2] = binary[3] ^ gray[2];
    assign binary[1] = binary[2] ^ gray[1];
    assign binary[0] = binary[1] ^ gray[0];
endmodule

// Testbench
module tb_gray_binary;
    reg  [3:0] gray;
    wire [3:0] binary;
    gray_to_binary dut(.gray(gray), .binary(binary));
    integer i;
    initial begin
        $display("Gray   | Binary | Expected");
        // Test all 16 Gray codes
        for(i=0; i<16; i=i+1) begin
            // Generate Gray code from binary i
            gray = i ^ (i >> 1); #5;
            $display("%b |  %b  |    %0d", gray, binary, i);
        end
    end
endmodule

module lzc_8bit(
    input  wire [7:0] d,
    output reg  [3:0] lz_count,  // 0-8 leading zeros
    output reg        all_zero   // all bits are zero
);
    always @(*) begin
        all_zero = 1'b0;
        casez (d)
            8'b1xxxxxxx: lz_count = 4'd0;
            8'b01xxxxxx: lz_count = 4'd1;
            8'b001xxxxx: lz_count = 4'd2;
            8'b0001xxxx: lz_count = 4'd3;
            8'b00001xxx: lz_count = 4'd4;
            8'b000001xx: lz_count = 4'd5;
            8'b0000001x: lz_count = 4'd6;
            8'b00000001: lz_count = 4'd7;
            8'b00000000: begin lz_count = 4'd8; all_zero = 1'b1; end
            default:     lz_count = 4'd0;
        endcase
    end
endmodule

module tb_lzc;
    reg  [7:0] d;
    wire [3:0] lz;
    wire       az;
    lzc_8bit dut(.d(d),.lz_count(lz),.all_zero(az));
    initial begin
        $display("D        | LZ | AllZero");
        d=8'h00; #5; $display("%b | %0d  |    %b", d, lz, az);
        d=8'h01; #5; $display("%b | %0d  |    %b", d, lz, az);
        d=8'h0F; #5; $display("%b | %0d  |    %b", d, lz, az);
        d=8'h80; #5; $display("%b | %0d  |    %b", d, lz, az);
        d=8'hFF; #5; $display("%b | %0d  |    %b", d, lz, az);
        d=8'h10; #5; $display("%b | %0d  |    %b", d, lz, az);
    end
endmodule
